// Import required libraries
import { ethers } from 'ethers';

// Initialize provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// ERC20 token ABI
const erc20Abi = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function transferFrom(address sender, address recipient, uint256 amount) external returns (bool)"
];

// DEX contract ABI
const dexAbi = [
  "function swap(address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOutMin, address to) external"
];

// ERC20 token addresses
const tokenAAddress = '0xTokenAAddress'; // Replace with actual token address
const tokenBAddress = '0xTokenBAddress'; // Replace with actual token address

// DEX contract address
const exchangeAddress = '0xExchangeAddress'; // Replace with actual DEX contract address

// Approve tokens for swapping
async function approveTokens(tokenAddress, spenderAddress) {
  const tokenContract = new ethers.Contract(tokenAddress, erc20Abi, signer);
  const maxApprovalAmount = ethers.constants.MaxUint256;
  
  const currentAllowance = await tokenContract.allowance(await signer.getAddress(), spenderAddress);
  if (currentAllowance.lt(maxApprovalAmount)) {
    const tx = await tokenContract.approve(spenderAddress, maxApprovalAmount);
    await tx.wait();
    console.log("Tokens approved for maximum amount.");
  } else {
    console.log("Tokens are already approved for maximum amount.");
  }
}

// Execute token swap
async function swapTokens(tokenIn, tokenOut, amountIn, amountOutMin) {
  const exchangeContract = new ethers.Contract(exchangeAddress, dexAbi, signer);
  const recipient = await signer.getAddress();

  const tx = await exchangeContract.swap(tokenIn, tokenOut, amountIn, amountOutMin, recipient);
  await tx.wait();
  console.log("Token swap executed successfully.");
}

// Example usage
async function executeTokenSwap() {
  await approveTokens(tokenAAddress, exchangeAddress);
  await swapTokens(tokenAAddress, tokenBAddress, ethers.utils.parseUnits("1.0", 18), ethers.utils.parseUnits("0.9", 18));
}

// Initiate swap
executeTokenSwap().catch(console.error);